const extractJsonObject = (text) => {
  const source = String(text || '').trim();
  if (!source) {
    return null;
  }

  try {
    return JSON.parse(source);
  } catch {
    const match = source.match(/\{[\s\S]*\}/);
    if (!match) {
      return null;
    }

    try {
      return JSON.parse(match[0]);
    } catch {
      return null;
    }
  }
};

const extractFirstStringDeep = (value) => {
  if (typeof value === 'string' && value.trim()) {
    return value.trim();
  }

  if (Array.isArray(value)) {
    for (const item of value) {
      const found = extractFirstStringDeep(item);
      if (found) {
        return found;
      }
    }

    return '';
  }

  if (value && typeof value === 'object') {
    if (typeof value.output_text === 'string' && value.output_text.trim()) {
      return value.output_text.trim();
    }

    for (const key of ['text', 'content', 'output', 'message']) {
      if (key in value) {
        const found = extractFirstStringDeep(value[key]);
        if (found) {
          return found;
        }
      }
    }

    for (const item of Object.values(value)) {
      const found = extractFirstStringDeep(item);
      if (found) {
        return found;
      }
    }
  }

  return '';
};

const buildAnnouncementGlossaryPrompt = () =>
  ANNOUNCEMENT_TRANSLATION_GLOSSARY.map(
    ({ source, az, ru }) => `- "${source}" => az: "${az}", ru: "${ru}"`,
  ).join('\n');

const applyAnnouncementGlossary = (text, language) => {
  const sourceText = String(text || '');
  if (!sourceText) {
    return '';
  }

  const glossaryKey = language === 'az' ? 'az' : language === 'ru' ? 'ru' : null;
  if (!glossaryKey) {
    return sourceText;
  }

  return ANNOUNCEMENT_TRANSLATION_GLOSSARY
    .slice()
    .sort((left, right) => right.source.length - left.source.length)
    .reduce((result, item) => result.replaceAll(item.source, item[glossaryKey]), sourceText);
};

const generateAnnouncementTranslationsWithOpenAI = async (message, sourceLanguage = 'en') => {
  const apiKey = process.env.OPENAI_API_KEY;
  if (!apiKey) {
    throw new HttpError(500, 'OPENAI_API_KEY is missing.');
  }

  const response = await fetch('https://api.openai.com/v1/responses', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model: 'gpt-4o-mini',
      input:
        `Translate the following announcement into Azerbaijani (az), English (en), and Russian (ru). ` +
        `Preserve meaning, tone, and line breaks. Use the glossary exactly when these terms appear. ` +
        `Glossary:\n${buildAnnouncementGlossaryPrompt()}\n` +
        `Return only JSON with keys az, en, ru. ` +
        `The source language is ${sourceLanguage}. Announcement:\n${message}`,
      text: {
        format: {
          type: 'json_object',
        },
      },
    }),
  });

  if (!response.ok) {
    throw new HttpError(response.status, 'OpenAI translation request failed.');
  }

  const payload = await response.json();
  const responseText = extractFirstStringDeep(payload);
  const parsed = extractJsonObject(responseText);
  if (!parsed || typeof parsed !== 'object') {
    throw new HttpError(500, 'OpenAI translation response was invalid.');
  }

  return {
    az: applyAnnouncementGlossary(String(parsed.az || '').trim(), 'az'),
    en: String(parsed.en || '').trim(),
    ru: applyAnnouncementGlossary(String(parsed.ru || '').trim(), 'ru'),
    usedFallback: false,
  };
};

const generateAnnouncementTranslations = async (message, sourceLanguage = 'en') => {
  const normalizedMessage = String(message || '').trim();
  const normalizedSourceLanguage = ['az', 'en', 'ru'].includes(String(sourceLanguage)) ? String(sourceLanguage) : 'en';
  const fallback = {
    az: normalizedMessage,
    en: normalizedMessage,
    ru: normalizedMessage,
    usedFallback: true,
  };

  if (!normalizedMessage) {
    return fallback;
  }

  try {
    if (process.env.OPENAI_API_KEY) {
      const translated = await generateAnnouncementTranslationsWithOpenAI(normalizedMessage, normalizedSourceLanguage);
      if (translated.az && translated.en && translated.ru) {
        return translated;
      }
    }
  } catch {
    // Fall through to Gemini and finally to manual fallback.
  }

  try {
    const ai = await getGeminiClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents:
        `Translate the following announcement into Azerbaijani (az), English (en), and Russian (ru). ` +
        `Preserve meaning, tone, line breaks, and keep it concise. ` +
        `Use the glossary exactly when these terms appear.\n${buildAnnouncementGlossaryPrompt()}\n` +
        `The source language is ${normalizedSourceLanguage}. ` +
        `Return only valid JSON like {"az":"...","en":"...","ru":"..."}. ` +
        `Announcement:\n${normalizedMessage}`,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
      },
    });

    const parsed = extractJsonObject(response.text);
    if (!parsed || typeof parsed !== 'object') {
      return fallback;
    }

    return {
      az: applyAnnouncementGlossary(String(parsed.az || fallback.az).trim() || fallback.az, 'az'),
      en: String(parsed.en || fallback.en).trim() || fallback.en,
      ru: applyAnnouncementGlossary(String(parsed.ru || fallback.ru).trim() || fallback.ru, 'ru'),
      usedFallback: false,
    };
  } catch {
    return fallback;
  }
};

