const createNomination = async (admin, currentUser, body) => {
  await requireRole(admin, currentUser.id, 'Instructor');

  const gameCode = String(body.gameCode || '').trim();
  const teams = String(body.teams || '').trim();
  const matchDate = String(body.matchDate || '').trim();
  const matchTime = String(body.matchTime || '').trim();
  const venue = String(body.venue || '').trim();
  const refereeIds = ensureDistinctReferees(body.refereeIds || []);
  const seasonId = normalizeSeasonId(body.seasonId) || inferSeasonIdFromDate(matchDate);

  if (!gameCode || !teams || !matchDate || !matchTime || !venue) {
    throw new HttpError(400, 'Fill in game number, teams, date, time and venue.');
  }

  const assignableOfficials = await requireAssignableOfficials(admin, refereeIds);
  await assertUsersAvailableOnMatchDate(admin, refereeIds, matchDate, 'officials');
  const officialMap = new Map(assignableOfficials.map((official) => [official.id, official]));
  const respondedAt = new Date().toISOString();
  const reportDeadlineAt = createDeadlineDate(matchDate, matchTime)?.toISOString() || null;
  const shouldAutoAcceptAssignments = hasMatchStarted(matchDate, matchTime);

  const { data: inserted, error } = await admin
    .from('nominations')
    .insert({
      created_by: currentUser.id,
      season_id: seasonId,
      game_code: gameCode,
      teams,
      match_date: matchDate,
      match_time: matchTime,
      venue,
    })
    .select('*')
    .single();

  if (error || !inserted) {
    throw new HttpError(500, 'Failed to create nomination.');
  }

  const slotsResponse = await admin.from('nomination_referees').insert(
    refereeIds.map((refereeId, index) => {
      const assignedOfficial = officialMap.get(refereeId);
      const isSelfAssignedInstructor = assignedOfficial?.id === currentUser.id && assignedOfficial.role === 'Instructor';
      const shouldAcceptImmediately = shouldAutoAcceptAssignments || isSelfAssignedInstructor;

      return {
        nomination_id: inserted.id,
        referee_id: refereeId,
        slot_number: index + 1,
        status: shouldAcceptImmediately ? ASSIGNMENT_STATUS.ACCEPTED : ASSIGNMENT_STATUS.PENDING,
        report_deadline_at: reportDeadlineAt,
        responded_at: shouldAcceptImmediately ? respondedAt : null,
      };
    }),
  );

  if (slotsResponse.error) {
    await admin.from('nominations').delete().eq('id', inserted.id);
    throw new HttpError(500, 'Failed to assign referees to the game.');
  }

  void sendPushNotifications(admin, refereeIds, {
    kind: 'assignment',
    title: '📋 New assignment',
    body: `You are assigned to ${teams}.`,
    path: '/(tabs)/nominations',
    data: {
      nominationId: inserted.id,
    },
  }).catch((pushError) => {
    console.error('[push] Failed to send assignment notification.', pushError);
  });

  void listProfilesByRoles(admin, ['Instructor'])
    .then((profiles) =>
      sendPushNotifications(
        admin,
        profiles.filter((profile) => profile.id !== currentUser.id).map((profile) => profile.id),
        {
          kind: 'new-game-created',
          title: '🏀 New game created',
          body: `${currentUser.full_name} added a new game: ${teams}.`,
          path: '/(tabs)/nominations',
          data: {
            nominationId: inserted.id,
          },
        },
      ),
    )
    .catch((pushError) => {
      console.error('[push] Failed to send new game notification.', pushError);
    });

  void listProfilesByRoles(admin, ['TO Supervisor'])
    .then((profiles) =>
      sendPushNotifications(admin, profiles.map((profile) => profile.id), {
        kind: 'to-selection',
        title: '👥 TO crew needed',
        body: `Choose the TO crew for ${teams}.`,
        path: '/(tabs)/nominations',
        data: {
          nominationId: inserted.id,
        },
      }),
    )
    .catch((pushError) => {
      console.error('[push] Failed to send TO selection notification.', pushError);
    });

  clearGameDataCaches();
  const nominations = await getInstructorNominationsData(admin, currentUser.id, true);
  return nominations.find((nomination) => nomination.id === inserted.id);
};

const replaceNominationReferee = async (admin, currentUser, nominationId, slotNumber, refereeId) => {
  await requireRole(admin, currentUser.id, 'Instructor');
  const nomination = await requireNominationOwner(admin, nominationId, currentUser.id);
  await expirePendingAssignments(admin, [nominationId]);
  const [assignedOfficial] = await requireAssignableOfficials(admin, [refereeId]);
  await assertUsersAvailableOnMatchDate(admin, [refereeId], nomination.match_date, 'officials');
  const isSelfAssignedInstructor = assignedOfficial.id === currentUser.id && assignedOfficial.role === 'Instructor';

  const slot = await requireSingle(
    admin.from('nomination_referees').select('*').eq('nomination_id', nominationId).eq('slot_number', slotNumber),
    'Nomination slot not found.',
    'Failed to load nomination slot.',
  );

  if (slot.status === ASSIGNMENT_STATUS.ACCEPTED) {
    throw new HttpError(400, 'Accepted referee cannot be replaced from this screen.');
  }

  const duplicate = await maybeSingle(
    admin
      .from('nomination_referees')
      .select('id')
      .eq('nomination_id', nominationId)
      .eq('referee_id', refereeId)
      .neq('slot_number', slotNumber)
      .limit(1),
    'Failed to validate nomination slot.',
  );

  if (duplicate) {
    throw new HttpError(409, 'This referee is already assigned to the game.');
  }

  const reportDeadlineAt = createDeadlineDate(nomination.match_date, nomination.match_time)?.toISOString() || null;
  const shouldAutoAcceptAssignment = hasMatchStarted(nomination.match_date, nomination.match_time);
  await removeReportsForRefereeChange(admin, nominationId, slot.referee_id, refereeId);
  await createReplacementNotice(admin, nominationId, slotNumber, slot.referee_id, refereeId, currentUser.id);

  const { error } = await admin
    .from('nomination_referees')
    .update({
      referee_id: refereeId,
      status: shouldAutoAcceptAssignment || isSelfAssignedInstructor ? ASSIGNMENT_STATUS.ACCEPTED : ASSIGNMENT_STATUS.PENDING,
      report_deadline_at: reportDeadlineAt,
      responded_at: shouldAutoAcceptAssignment || isSelfAssignedInstructor ? new Date().toISOString() : null,
    })
    .eq('nomination_id', nominationId)
    .eq('slot_number', slotNumber);

  if (error) {
    throw new HttpError(500, 'Failed to replace referee.');
  }

  clearGameDataCaches();
  const nominations = await getInstructorNominationsData(admin, currentUser.id, true);
  return nominations.find((nomination) => nomination.id === nominationId);
};

const editNominationOfficials = async (admin, currentUser, nominationId, body) => {
  await requireRole(admin, currentUser.id, 'Instructor');
  const nomination = await requireNominationOwner(admin, nominationId, currentUser.id);
  const normalizedRefereeIds = ensureDistinctReferees(body.refereeIds || []);
  const nextTeams = String(body.teams || '').trim() || nomination.teams;
  const nextMatchDate = String(body.matchDate || '').trim() || nomination.match_date;
  const nextMatchTime = String(body.matchTime || '').trim() || nomination.match_time;
  const nextVenue = String(body.venue || '').trim() || nomination.venue;
  const nextSeasonId = normalizeSeasonId(body.seasonId) || nomination.season_id || inferSeasonIdFromDate(nextMatchDate);
  const assignableOfficials = await requireAssignableOfficials(admin, normalizedRefereeIds);
  await assertUsersAvailableOnMatchDate(admin, normalizedRefereeIds, nextMatchDate, 'officials');
  const officialMap = new Map(assignableOfficials.map((official) => [official.id, official]));
  const currentSlots = await listAssignmentsByNominationIds(admin, [nominationId]);

  if (!nextTeams || !nextMatchDate || !nextMatchTime || !nextVenue) {
    throw new HttpError(400, 'Fill in teams, date, time and venue.');
  }

  if (currentSlots.length !== 3) {
    throw new HttpError(409, 'This game does not have a complete crew to edit.');
  }

  const slotMap = new Map(currentSlots.map((slot) => [Number(slot.slot_number), slot]));
  const reportDeadlineAt = createDeadlineDate(nextMatchDate, nextMatchTime)?.toISOString() || null;
  const respondedAt = new Date().toISOString();
  const shouldAutoAcceptAssignments = hasMatchStarted(nextMatchDate, nextMatchTime);

  const nominationUpdateResponse = await admin
    .from('nominations')
    .update({
      teams: nextTeams,
      match_date: nextMatchDate,
      match_time: nextMatchTime,
      venue: nextVenue,
      season_id: nextSeasonId,
    })
    .eq('id', nominationId);

  if (nominationUpdateResponse.error) {
    throw new HttpError(500, 'Failed to update game details.');
  }

  for (const [index, refereeId] of normalizedRefereeIds.entries()) {
    const slotNumber = index + 1;
    const existingSlot = slotMap.get(slotNumber);
    if (!existingSlot) {
      throw new HttpError(404, 'Nomination slot not found.');
    }

    const assignedOfficial = officialMap.get(refereeId);
    const isSelfAssignedInstructor = assignedOfficial?.id === currentUser.id && assignedOfficial.role === 'Instructor';
    const isSameOfficial = existingSlot.referee_id === refereeId;

    await removeReportsForRefereeChange(admin, nominationId, existingSlot.referee_id, refereeId);
    await createReplacementNotice(admin, nominationId, slotNumber, existingSlot.referee_id, refereeId, currentUser.id);

    const nextStatus = isSameOfficial
      ? existingSlot.status
      : shouldAutoAcceptAssignments || isSelfAssignedInstructor
        ? ASSIGNMENT_STATUS.ACCEPTED
        : ASSIGNMENT_STATUS.PENDING;

    const nextRespondedAt = isSameOfficial
      ? existingSlot.responded_at || null
      : shouldAutoAcceptAssignments || isSelfAssignedInstructor
        ? respondedAt
        : null;

    const { error } = await admin
      .from('nomination_referees')
      .update({
        referee_id: refereeId,
        status: nextStatus,
        responded_at: nextRespondedAt,
        report_deadline_at: reportDeadlineAt,
      })
      .eq('nomination_id', nominationId)
      .eq('slot_number', slotNumber);

    if (error) {
      throw new HttpError(500, 'Failed to update the crew.');
    }
  }

  clearGameDataCaches();
  const nominations = await getInstructorNominationsData(admin, currentUser.id, true);
  return nominations.find((item) => item.id === nominationId);
};

const assignNominationTOs = async (admin, currentUser, nominationId, toIds) => {
  await requireRole(admin, currentUser.id, 'TO Supervisor');
  const nomination = await requireSingle(
    admin.from('nominations').select('id, match_date, match_time').eq('id', nominationId),
    'Nomination not found.',
    'Failed to load nomination.',
  );

  const isPastMatch = hasMatchStarted(nomination.match_date, nomination.match_time);
  const existingAssignments = (await listTOAssignmentsByNominationIds(admin, [nominationId])).filter((assignment) =>
    TO_CREW_SLOT_NUMBERS.includes(Number(assignment.slot_number)),
  );
  const existingAssignmentsBySlot = new Map(existingAssignments.map((assignment) => [Number(assignment.slot_number), assignment]));

  if (isPastMatch) {
    const normalizedTOSelections = normalizeTOSlotSelections(toIds, TO_CREW_SLOT_NUMBERS.length, 'TO users');
    const mergedTOSelections = TO_CREW_SLOT_NUMBERS.map(
      (slotNumber, index) => existingAssignmentsBySlot.get(slotNumber)?.to_id || normalizedTOSelections[index] || '',
    );

    existingAssignmentsBySlot.forEach((assignment, slotNumber) => {
      const slotIndex = TO_CREW_SLOT_NUMBERS.indexOf(slotNumber);
      const selectedToId = slotIndex >= 0 ? mergedTOSelections[slotIndex] : '';
      if (selectedToId !== assignment.to_id) {
        throw new HttpError(409, 'Assigned TO officials cannot be changed after the match starts.');
      }
    });

    const additions = mergedTOSelections
      .map((toId, index) => ({
        toId,
        slotNumber: TO_CREW_SLOT_NUMBERS[index],
      }))
      .filter((item) => item.toId && !existingAssignmentsBySlot.has(item.slotNumber));

    if (!additions.length) {
      throw new HttpError(400, 'Choose at least one TO user for an empty slot.');
    }

    await requireTOUsers(
      admin,
      additions.map((item) => item.toId),
    );
    await assertUsersAvailableOnMatchDate(
      admin,
      additions.map((item) => item.toId),
      nomination.match_date,
      'TO users',
    );

    const { error: insertError } = await admin.from('nomination_tos').insert(
      additions.map((item) => ({
        nomination_id: nominationId,
        to_id: item.toId,
        slot_number: item.slotNumber,
        assigned_by: currentUser.id,
        status: ASSIGNMENT_STATUS.ACCEPTED,
        responded_at: new Date().toISOString(),
      })),
    );

    if (insertError) {
      throw new HttpError(500, 'Failed to assign TO crew.');
    }
  } else {
    const normalizedTOIds = ensureDistinctTOs(toIds, TO_CREW_SLOT_NUMBERS.length, 'TO users');
    await requireTOUsers(admin, normalizedTOIds);
    await assertUsersAvailableOnMatchDate(admin, normalizedTOIds, nomination.match_date, 'TO users');

    const { error: deleteError } = await admin
      .from('nomination_tos')
      .delete()
      .eq('nomination_id', nominationId)
      .in('slot_number', TO_CREW_SLOT_NUMBERS);
    if (deleteError) {
      throw new HttpError(500, 'Failed to reset TO crew.');
    }

    const { error: insertError } = await admin.from('nomination_tos').insert(
      normalizedTOIds.map((toId, index) => ({
        nomination_id: nominationId,
        to_id: toId,
        slot_number: TO_CREW_SLOT_NUMBERS[index],
        assigned_by: currentUser.id,
        status: ASSIGNMENT_STATUS.PENDING,
        responded_at: null,
      })),
    );

    if (insertError) {
      throw new HttpError(500, 'Failed to assign TO crew.');
    }
  }

  if (
    nextTeams !== nomination.teams ||
    nextMatchDate !== nomination.match_date ||
    nextMatchTime !== nomination.match_time ||
    nextVenue !== nomination.venue
  ) {
    const { error: nominationUpdateError } = await admin
      .from('nominations')
      .update({
        teams: nextTeams,
        match_date: nextMatchDate,
        match_time: nextMatchTime,
        venue: nextVenue,
      })
      .eq('id', nominationId);

    if (nominationUpdateError) {
      throw new HttpError(500, 'Failed to update game details.');
    }
  }

  clearGameDataCaches();
  const nominations = await getInstructorNominationsData(admin, currentUser.id, true);
  return nominations.find((item) => item.id === nominationId);
};

